+export function matchEach<const input, output = symbols.unset>(
+  value: input
+): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<input, output>;
+export function matchEach(value: unknown = noInput): MatchEach<any, any> {
+  return new MatchEachExpression(value, []) as any;
+}
+
+class MatchEachExpression {
+  constructor(private input: unknown, private clauses: readonly Clause[]) {}
+
+  with(...args: any[]): MatchEachExpression {
+    const handler = args[args.length - 1];
+    const patterns: Pattern<any>[] = [args[0]];
+    let predicate: ((value: unknown) => unknown) | undefined;
+
+    if (args.length === 3 && typeof args[1] === 'function') {
+      predicate = args[1];
+    } else if (args.length > 2) {
+      patterns.push(...args.slice(1, -1));
+    }
+    return new MatchEachExpression(this.input, [
+      ...this.clauses,
+      { type: 'with', patterns, predicate, handler },
+    ]);
+  }
+
+  when(predicate: (value: unknown) => unknown, handler: (value: unknown) => unknown) {
+    return new MatchEachExpression(this.input, [
+      ...this.clauses,
+      { type: 'when', predicate, handler },
+    ]);
+  }
+
+  tap(callback: (result: unknown) => void) {
+    return new MatchEachExpression(this.input, [...this.clauses, { type: 'tap', callback }]);
+  }
+
+  otherwise(handler: (value: unknown) => unknown): unknown[] {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [handler(this.input)];
+  }
+
+  exhaustive(unexpectedValueHandler = defaultCatcher): unknown[] {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [unexpectedValueHandler(this.input)];
+  }
+
+  run(): unknown[] {
+    return this.exhaustive();
+  }
+
+  returnType() {
+    return this;
+  }
+
+  narrow() {
+    return this;
+  }
+
+  toFunction() {
+    return (input: unknown) => {
+      const results = this.evaluate(input);
+      if (!results.length) defaultCatcher(input);
+      return results;
+    };
+  }
+
+  toExhaustiveFunction() {
+    return this.toFunction();
+  }
+
+  toPartialFunction() {
+    return (input: unknown) => {
+      const results = this.evaluate(input);
+      return results.length ? results : undefined;
+    };
+  }
+
+  private evaluate(input: unknown): unknown[] {
+    const results: unknown[] = [];
+    for (const clause of this.clauses) {
+      if (clause.type === 'tap') {
+        results.forEach(clause.callback);
+      } else if (clause.type === 'when') {
+        if (clause.predicate(input)) results.push(clause.handler(input));
+      } else {
